1	type Item = { type: string; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Step = QuoteStep;
4	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const CURSE_SURCHARGE = 0.5;
9	const COMPONENT_BASE_PREMIUM = 25;
10	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
11	const COMPONENT_BLOCK_SIZE = 3;
12	
13	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	};
17	
18	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
19	
20	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
21	
22	const mainItemPremium = (item: Item): number => {
23	  const base = MAIN_ITEM_BASE_PREMIUM[item.type];
24	  const curse = item.cursed ? base * CURSE_SURCHARGE : 0;
25	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
26	  return base + curse + firstInsurance;
27	};
28	
29	const componentGroupBase = (count: number): number => {
30	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
31	  const leftover = count % COMPONENT_BLOCK_SIZE;
32	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
33	};
34	
35	const componentCountsByType = (components: Item[]): Map<string, number> => {
36	  const counts = new Map<string, number>();
37	  for (const item of components) {
38	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	  }
40	  return counts;
41	};
42	
43	const sumComponentPremiums = (components: Item[]): number =>
44	  [...componentCountsByType(components).values()].reduce(
45	    (total, count) => total + componentGroupBase(count) * (1 + FIRST_INSURANCE_SURCHARGE),
46	    0,
47	  );
48	
49	const sumItemPremiums = (items: Item[]): number => {
50	  const mainItems = items.filter(isMainItem);
51	  const components = items.filter((i) => !isMainItem(i));
52	  const mainTotal = mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);
53	  return mainTotal + sumComponentPremiums(components);
54	};
55	
56	const priceQuote = (step: QuoteStep): { premium: number } => ({
57	  premium: ceilWithEpsilon(sumItemPremiums(step.items) + PROCESSING_FEE),
58	});
59	
60	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
61	  results: scenario.steps.map(priceQuote),
62	});
63

